import { BeltHooks } from './hooks.js';
import type {
  BeltConfig,
  BeltContext,
  BeltPlugin,
  CheckResult,
  CommandDefinition,
} from './types.js';

export class Belt {
  readonly hooks: BeltHooks;
  readonly config: BeltConfig;

  private plugins: BeltPlugin[] = [];
  private commands = new Map<string, CommandDefinition>();
  private initialized = false;
  private context: BeltContext;

  constructor(config: BeltConfig = {}) {
    this.hooks = new BeltHooks();
    this.config = {
      rootDir: process.cwd(),
      verbose: false,
      ...config,
    };
    this.context = this.createContext();
  }

  private createContext(): BeltContext {
    return {
      cwd: this.config.rootDir ?? process.cwd(),
      config: this.config,
      hooks: this.hooks,
      log: {
        info: (msg) => this.log(msg, 'info'),
        warn: (msg) => this.log(msg, 'warn'),
        error: (msg) => this.log(msg, 'error'),
        debug: (msg) => this.log(msg, 'debug'),
      },
    };
  }

  private log(message: string, level: 'info' | 'warn' | 'error' | 'debug') {
    this.hooks.log.call(message, level);

    if (level === 'debug' && !this.config.verbose) return;

    const prefix = {
      info: '\x1b[36m[info]\x1b[0m',
      warn: '\x1b[33m[warn]\x1b[0m',
      error: '\x1b[31m[error]\x1b[0m',
      debug: '\x1b[90m[debug]\x1b[0m',
    }[level];

    console.log(`${prefix} ${message}`);
  }

  use(plugin: BeltPlugin): this {
    if (this.initialized) {
      throw new Error(`Cannot add plugin "${plugin.name}" after initialization`);
    }
    this.plugins.push(plugin);
    return this;
  }

  registerCommand(command: CommandDefinition): this {
    this.commands.set(command.id, command);
    return this;
  }

  getCommands(): CommandDefinition[] {
    return Array.from(this.commands.values());
  }

  async initialize(): Promise<void> {
    if (this.initialized) return;

    for (const plugin of this.plugins) {
      await plugin.apply(this);
    }

    const commands = await this.hooks.registerCommands.promise(
      Array.from(this.commands.values()),
      this.context,
    );

    this.commands.clear();
    for (const cmd of commands) {
      this.commands.set(cmd.id, cmd);
    }

    await this.hooks.initialize.promise(this.context);
    this.initialized = true;
  }

  async runCommand(commandId: string, args?: string[]): Promise<void> {
    await this.initialize();

    const command = this.commands.get(commandId);
    if (!command) {
      throw new Error(`Command "${commandId}" not found`);
    }

    await this.hooks.beforeCommand.promise(command, this.context);
    await command.handler(this.context, args);
    await this.hooks.afterCommand.promise(command, this.context);
  }

  async check(): Promise<CheckResult[]> {
    await this.initialize();
    await this.hooks.beforeCheck.promise(this.context);

    let results: CheckResult[] = [];
    results = await this.hooks.checkResults.promise(results, this.context);

    await this.hooks.afterCheck.promise(results, this.context);
    return results;
  }

  async shutdown(): Promise<void> {
    await this.hooks.shutdown.promise(this.context);
  }
}

export function createBelt(config?: BeltConfig): Belt {
  return new Belt(config);
}

