import path from 'node:path';
import type { BeltPlugin } from '@belt/core';
import { discoverImports } from './discover.js';
import { generateDeclarations } from './generate.js';
import type { SyncTypesOptions } from './types.js';
import { writeDeclarations } from './write.js';

export function syncTypesPlugin(options: SyncTypesOptions): BeltPlugin {
  const {
    sourceProject,
    importPatterns = ['~/**'],
    ignorePatterns = [],
    outputPath = '@types/external.d.ts',
    maxDepth = 4,
  } = options;

  return {
    name: 'sync-types',
    version: '0.1.0',

    apply(belt) {
      belt.registerCommand({
        id: 'sync-types',
        name: 'Sync Types',
        description: 'Generate type declarations from external project',
        category: 'Quality',
        async handler(ctx) {
          const resolvedSource = path.resolve(ctx.cwd, sourceProject);
          const resolvedOutput = path.resolve(ctx.cwd, outputPath);

          ctx.log.info(`Syncing types from ${resolvedSource}`);

          const imports = discoverImports({
            sourceDir: path.join(ctx.cwd, 'src'),
            patterns: importPatterns,
            ignore: ignorePatterns,
          });

          if (imports.length === 0) {
            ctx.log.warn('No imports found matching patterns');
            return;
          }

          ctx.log.info(`Found ${imports.length} imports to process`);

          const declarations = await generateDeclarations({
            imports,
            projectPath: resolvedSource,
            maxDepth,
            cwd: ctx.cwd,
          });

          await writeDeclarations(declarations, resolvedOutput);

          ctx.log.info(`Generated declarations at ${outputPath}`);
        },
      });
    },
  };
}

