     4→
     5→export type ErrorLike = {
     6→  message: string;
     7→  stack: string;
     8→};
     9→
    10→export function isErrorLike(value: any): value is ErrorLike {
    11→  return Boolean(typeof value?.message === 'string' && typeof value?.stack === 'string');
    12→}
    13→
    14→/**
    15→ * Check if we're running in Bun (which has captureStackTrace but with different behavior)
    16→ */
    17→const isBun = typeof (globalThis as any).Bun !== 'undefined';
    18→
    19→/**
    20→ * Check if Error.captureStackTrace is available and works correctly
    21→ * Note: Bun has captureStackTrace but the second argument causes undefined stack
    22→ */
    23→export const hasCaptureStackTrace = typeof Error.captureStackTrace === 'function';
    24→
    25→/**
    26→ * Universal stack trace capture that works in both V8 (Node.js) and JSC (Bun)
    27→ * In V8: uses Error.captureStackTrace for clean stack traces
    28→ * In Bun: uses captureStackTrace without second arg (avoids undefined stack bug)
    29→ */
    30→export function captureStackTrace(targetError: Error, constructorOpt?: Function): void {
    31→  if (!hasCaptureStackTrace) {
    32→    // No captureStackTrace available - keep original stack
    33→    return;
    34→  }
    35→
    36→  if (isBun) {
    37→    // Bun has a bug where passing constructorOpt makes stack undefined
    38→    // Just call without the second argument to get a valid stack
    39→    Error.captureStackTrace(targetError);
    40→  } else {
    41→    // Node.js / V8 - full support
    42→    Error.captureStackTrace(targetError, constructorOpt);
    43→  }
    44→}
    45→
    46→export function assertErrorLike(value: unknown): asserts value is ErrorLike {
    47→  if (!isErrorLike(value)) {
    48→    throw value;
    49→  }
    50→}
    51→
    52→const IS_NOT_PRODUCTION = typeof process === 'object' && process.env?.NODE_ENV !== 'production';
    53→
    54→export type InvariantMessage =
    55→  | string
    56→  | ((typeName: string) => string)
    57→  | {
    58→      message?: string;
    59→      stack?: string;
    60→    };
    61→
    62→export function parseInvariantMessage(
    63→  errorOrMessage: InvariantMessage | undefined,
    64→  value: unknown,
    65→) {
    66→  if (typeof errorOrMessage === 'string') return errorOrMessage;
    67→  if (
    68→    errorOrMessage &&
    69→    typeof errorOrMessage === 'object' &&
    70→    typeof errorOrMessage.message === 'string'
    71→  ) {
    72→    return errorOrMessage.message;
    73→  }
    74→  if (typeof errorOrMessage === 'function') {
