import { createBelt } from '@belt/core';
import { syncTypesPlugin } from '@belt/plugin-sync-types';
import { typecheckPlugin } from '@belt/plugin-typecheck';
import { render } from 'ink';
import meow from 'meow';
import React from 'react';
import { App } from './app.js';

const help = `
  Usage
    $ belt [command] [options]

  Commands
    check        Run all quality checks
    typecheck    Run TypeScript type checking
    sync-types   Generate type declarations from external project
    ui           Launch interactive UI (default)

  Options
    --help       Show this help
    --version    Show version
    --verbose    Enable verbose output
    --cwd        Set working directory
    --source     Source project path (for sync-types)
    --pattern    Import pattern to match (for sync-types, default: ~/**)

  Examples
    $ belt check
    $ belt typecheck
    $ belt sync-types --source ../appSemPararv3
    $ belt sync-types --source ../appSemPararv3 --pattern "@semparar/**"
    $ belt
`;

export async function runCli(): Promise<void> {
  const cli = meow(help, {
    importMeta: import.meta,
    flags: {
      verbose: { type: 'boolean', default: false },
      cwd: { type: 'string', default: process.cwd() },
      source: { type: 'string' },
      pattern: { type: 'string' },
    },
  });

  const [command] = cli.input;
  const { verbose, cwd, source, pattern } = cli.flags;

  const belt = createBelt({ rootDir: cwd, verbose });
  belt.use(typecheckPlugin());

  if (source) {
    belt.use(
      syncTypesPlugin({
        sourceProject: source,
        importPatterns: pattern ? [pattern] : undefined,
      }),
    );
  }

  switch (command) {
    case 'check': {
      await belt.initialize();
      const results = await belt.check();

      const totalErrors = results.reduce((sum, r) => sum + r.errorCount, 0);
      const totalWarnings = results.reduce((sum, r) => sum + r.warningCount, 0);

      if (totalErrors > 0) {
        console.log(`\n\x1b[31m✖ ${totalErrors} errors, ${totalWarnings} warnings\x1b[0m\n`);
        process.exit(1);
      }
      console.log('\n\x1b[32m✓ All checks passed\x1b[0m\n');
      break;
    }

    case 'typecheck': {
      await belt.runCommand('typecheck');
      break;
    }

    case 'sync-types': {
      if (!source) {
        console.error('\x1b[31m✖ Missing --source option\x1b[0m');
        console.log('  Usage: belt sync-types --source <path-to-source-project>');
        process.exit(1);
      }
      await belt.runCommand('sync-types');
      break;
    }

    case 'ui':
    case undefined: {
      render(React.createElement(App, { belt }));
      break;
    }

    default: {
      console.error(`Unknown command: ${command}`);
      console.log(help);
      process.exit(1);
    }
  }
}

